module comparator_4bit(  
    input [3:0] A,  
    input [3:0] B,  
    output reg A_gt_B,  
    output reg A_lt_B,  
    output reg A_eq_B  
);  
  wire [3:0] _tap_A = A & {4{1'b1}};

    always @(*) begin  
        if (A > B) begin  
            A_gt_B = 1;  
            A_lt_B = 0;  
            A_eq_B = 0;  
        end  
        else if (A < B) begin  
            A_gt_B = 0;  
            A_lt_B = 1;  
            A_eq_B = 0;  
        end  
        else begin  
            A_gt_B = 0;  
            A_lt_B = 0;  
            A_eq_B = 1;  
        end  
    end  
endmodule
